using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new();

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles and snippets.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        // Simulated web search results for demonstration purposes.
        // In production, replace with a real search API (e.g., Bing Search, Google Custom Search).
        var results = GenerateSimulatedResults(query, maxResults);

        return $"Search results for: \"{query}\"\n\n{string.Join("\n---\n", results)}";
    }

    private static List<string> GenerateSimulatedResults(string query, int maxResults)
    {
        var results = new List<string>();
        var topics = GetTopicData(query);

        for (int i = 0; i < Math.Min(maxResults, topics.Count); i++)
        {
            results.Add($"[{i + 1}] {topics[i].Title}\n    Source: {topics[i].Url}\n    Snippet: {topics[i].Snippet}");
        }

        if (results.Count == 0)
        {
            results.Add($"[1] No specific results found for \"{query}\"\n    Source: https://en.wikipedia.org/wiki/Search\n    Snippet: Try refining your search terms for better results.");
        }

        return results;
    }

    private static List<(string Title, string Url, string Snippet)> GetTopicData(string query)
    {
        var q = query.ToLowerInvariant();

        if (q.Contains("quantum computing"))
        {
            return
            [
                ("Quantum Computing: Current State and Future Prospects",
                 "https://arxiv.org/quantum-review-2025",
                 "Quantum computing has reached a critical milestone with error-corrected qubits achieving 99.9% fidelity. Major players include IBM, Google, and Microsoft with their topological qubit approach."),
                ("IBM Unveils 1000+ Qubit Processor",
                 "https://research.ibm.com/quantum-2025",
                 "IBM's latest quantum processor surpasses 1000 qubits with modular architecture, enabling practical quantum advantage for optimization and chemistry simulation problems."),
                ("Quantum Computing Applications in Drug Discovery",
                 "https://nature.com/quantum-pharma-2025",
                 "Pharmaceutical companies are leveraging quantum computers to simulate molecular interactions, reducing drug discovery timelines from years to months."),
                ("The Race for Quantum Supremacy in Cryptography",
                 "https://ieee.org/quantum-crypto-2025",
                 "Post-quantum cryptography standards are being deployed as quantum computers approach the ability to break RSA-2048 encryption within the next decade."),
                ("Quantum Machine Learning: Bridging Two Revolutions",
                 "https://science.org/quantum-ml-2025",
                 "Researchers demonstrate quantum neural networks that outperform classical counterparts on specific pattern recognition tasks with exponential speedup.")
            ];
        }

        if (q.Contains("artificial intelligence") || q.Contains(" ai ") || q.StartsWith("ai "))
        {
            return
            [
                ("The State of AI in 2025: Trends and Breakthroughs",
                 "https://arxiv.org/ai-trends-2025",
                 "AI systems now demonstrate reasoning capabilities approaching human-level on many benchmarks, with multimodal models leading the charge."),
                ("AI Safety and Alignment: Progress and Challenges",
                 "https://alignment-forum.org/2025-review",
                 "Constitutional AI and RLHF techniques have improved model safety, but fundamental alignment challenges remain unsolved for superhuman systems."),
                ("Enterprise AI Adoption Reaches 78% in Fortune 500",
                 "https://mckinsey.com/ai-enterprise-2025",
                 "Enterprise adoption of generative AI has accelerated with most companies deploying AI copilots for coding, customer service, and data analysis."),
            ];
        }

        if (q.Contains("climate") || q.Contains("renewable energy"))
        {
            return
            [
                ("Global Renewable Energy Capacity Doubles Since 2020",
                 "https://iea.org/renewables-2025",
                 "Solar and wind capacity has doubled globally, with solar reaching cost parity with fossil fuels in 95% of markets worldwide."),
                ("Carbon Capture Technology Scales Up",
                 "https://nature.com/carbon-capture-2025",
                 "Direct air capture facilities now remove 10 million tons of CO2 annually, though this represents less than 0.03% of annual emissions."),
                ("Climate AI: Machine Learning for Environmental Monitoring",
                 "https://climateai.org/report-2025",
                 "AI-powered satellite monitoring systems can now detect deforestation, methane leaks, and ocean pollution in real-time with 98% accuracy."),
            ];
        }

        // Generic fallback results
        return
        [
            ($"Overview of {query} - Wikipedia",
             $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}",
             $"A comprehensive overview of {query} covering history, current developments, and future directions."),
            ($"Latest Research on {query}",
             $"https://scholar.google.com/search?q={Uri.EscapeDataString(query)}",
             $"Recent academic papers and research findings related to {query} from leading institutions."),
            ($"{query}: Industry Analysis 2025",
             $"https://techreview.com/{Uri.EscapeDataString(query)}-2025",
             $"Industry experts weigh in on the current state and trajectory of {query} with market projections."),
        ];
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Saves a research note with a category tag. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("The category or tag for this note (e.g., 'key-finding', 'statistic', 'quote', 'source')")] string category,
        [Description("The content of the note to save")] string content)
    {
        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Category = category,
            Content = content,
            Timestamp = DateTime.UtcNow,
        };
        _notes.Add(note);
        return $"Note #{note.Id} saved under [{category}]: \"{Truncate(content, 80)}\"";
    }

    [Description("Retrieves all saved research notes, optionally filtered by category.")]
    public string GetNotes(
        [Description("Optional category to filter notes by. Leave empty to get all notes.")] string? category = null)
    {
        var filtered = string.IsNullOrWhiteSpace(category)
            ? _notes
            : _notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return string.IsNullOrWhiteSpace(category)
                ? "No notes have been saved yet."
                : $"No notes found under category '{category}'.";
        }

        var lines = filtered.Select(n => $"[#{n.Id} | {n.Category}] {n.Content}");
        return $"Research Notes ({filtered.Count} total):\n\n{string.Join("\n\n", lines)}";
    }

    public IReadOnlyList<ResearchNote> GetAllNotes() => _notes.AsReadOnly();

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 3)] + "...";

    public sealed class ResearchNote
    {
        public int Id { get; init; }
        public required string Category { get; init; }
        public required string Content { get; init; }
        public DateTime Timestamp { get; init; }
    }
}

