        [Description("The category or tag for this note (e.g., 'key-finding', 'statistic', 'quote', 'source')")] string category,
        [Description("The content of the note to save")] string content)
    {
        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Category = category,
            Content = content,
            Timestamp = DateTime.UtcNow,
        };
        _notes.Add(note);
        return $"Note #{note.Id} saved under [{category}]: \"{Truncate(content, 80)}\"";
    }

    [Description("Retrieves all saved research notes, optionally filtered by category.")]
    public string GetNotes(
        [Description("Optional category to filter notes by. Leave empty to get all notes.")] string? category = null)
    {
        var filtered = string.IsNullOrWhiteSpace(category)
            ? _notes
            : _notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return string.IsNullOrWhiteSpace(category)
                ? "No notes have been saved yet."
                : $"No notes found under category '{category}'.";
        }

        var lines = filtered.Select(n => $"[#{n.Id} | {n.Category}] {n.Content}");
        return $"Research Notes ({filtered.Count} total):\n\n{string.Join("\n\n", lines)}";
    }

    public IReadOnlyList<ResearchNote> GetAllNotes() => _notes.AsReadOnly();

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 3)] + "...";

    public sealed class ResearchNote
    {
        public int Id { get; init; }
        public required string Category { get; init; }
        public required string Content { get; init; }
        public DateTime Timestamp { get; init; }
    }
}

