using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI.ChatCompletion;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Configure AI services
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(chatClientBuilder => chatClientBuilder
    .UseLogging()
    .Use(new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient()));

builder.Services.AddLogging(logging =>
{
    logging.SetMinimumLevel(LogLevel.Warning);
    logging.AddConsole();
});

using var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var logger = host.Services.GetRequiredService<ILoggerFactory>().CreateLogger("ResearchAgent");

// Create tool instances
var noteTakingTool = new NoteTakingTool();

// Register tools with the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(noteTakingTool.SaveNote),
    AIFunctionFactory.Create(noteTakingTool.GetNotes),
};

// Get the research topic
Console.Write("Enter a topic to research (or press Enter for 'quantum computing'): ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    topic = "quantum computing";
}

Console.WriteLine($"\n🔬 Researching: {topic}");
Console.WriteLine(new string('─', 50));

// Create the agent with system instructions
var systemPrompt = $"""
    You are a research assistant agent. Your goal is to thoroughly research the given topic
    by searching the web and taking organized notes.

    Follow this research workflow:
    1. Search for broad information about the topic
    2. Save key findings as notes with appropriate categories
    3. Search for more specific aspects (applications, challenges, future outlook)
    4. Save additional findings as notes
    5. Review all your notes
    6. Provide a comprehensive summary of your research

    Use categories like: 'key-finding', 'statistic', 'application', 'challenge', 'future-outlook', 'source'

    Be thorough but concise. Always cite your sources.
    """;

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = [.. tools],
};

// Run the agent loop using ChatClientAgent
var agent = new ChatClientAgent(chatClient, systemPrompt, chatOptions);

var agentOptions = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

Console.WriteLine("\n📡 Agent is researching...\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

string? finalResponse = null;
int stepCount = 0;

await foreach (var message in agent.InvokeStreamingAsync(history, agentOptions))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        finalResponse = message.Text;
    }

    stepCount++;
    logger.LogDebug("Agent step {Step}: Role={Role}, ContentLength={Length}",
        stepCount, message.Role, message.Text?.Length ?? 0);
}

// Display results
Console.WriteLine("═══════════════════════════════════════════════════");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════\n");

if (!string.IsNullOrEmpty(finalResponse))
{
    Console.WriteLine(finalResponse);
}
else
{
    Console.WriteLine("The agent completed research but did not produce a final summary.");
}

// Display collected notes
var notes = noteTakingTool.GetAllNotes();
if (notes.Count > 0)
{
    Console.WriteLine($"\n{"═══════════════════════════════════════════════════"}");
    Console.WriteLine($"📝 RESEARCH NOTES ({notes.Count} collected)");
    Console.WriteLine("═══════════════════════════════════════════════════\n");

    foreach (var note in notes)
    {
        Console.WriteLine($"  [{note.Category}] {note.Content}\n");
    }
}

Console.WriteLine($"\n✅ Research complete. Agent used {stepCount} steps.");

